// src/components/Navbar/Navbar.jsx
import React, { useState } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import './Navbar.css';

export default function Navbar() {
  const userRole = localStorage.getItem('userRole');
  const location = useLocation();
  const navigate = useNavigate();
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  // Scroll to Contact section
  const scrollToContact = () => {
    const el = document.getElementById('contact');
    if (el) el.scrollIntoView({ behavior: 'smooth' });
    setIsMenuOpen(false);
  };

  // Handle logout
  const handleLogout = () => {
    localStorage.removeItem('isLoggedIn');
    localStorage.removeItem('userRole');
    setIsMenuOpen(false);
    navigate('/login');
  };

  // Handle Order button
  const handleOrderClick = () => {
    const isLoggedIn = localStorage.getItem('isLoggedIn');
    navigate(isLoggedIn ? '/order' : '/login');
    setIsMenuOpen(false);
  };

  const navLinks = [
    { name: 'Home', path: '/home' },
    { name: 'Menu', path: '/menu' },
    { name: 'About', path: '/about' },
  ];

  return (
    <nav className="navbar">
      {/* Logo */}
      <Link
        to="/home"
        onClick={() => {
          setIsMenuOpen(false);
          window.scrollTo({ top: 0, behavior: 'smooth' });
        }}
      >
        <img src="Images/LOGO.jpg" alt="Restaurant Logo" className="logo" />
      </Link>

      {/* Navigation Links */}
      <ul className={`nav-links ${isMenuOpen ? 'active' : ''}`}>
        {navLinks.map(link => (
          <li key={link.path}>
            <Link
              to={link.path}
              onClick={() => {
                setIsMenuOpen(false);
                // Scroll to top if already on the page
                if (location.pathname === link.path) {
                  window.scrollTo({ top: 0, behavior: 'smooth' });
                }
              }}
            >
              {link.name}
            </Link>
          </li>
        ))}

        {/* Contact */}
        <li>
          {location.pathname === '/home' ? (
            <button className="menu-button" onClick={scrollToContact}>
              Contact
            </button>
          ) : (
            <Link
              to="/home"
              onClick={() => setTimeout(scrollToContact, 50)}
            >
              Contact
            </Link>
          )}
        </li>

        {/* Order Now */}
        <li>
          <button className="order-button" onClick={handleOrderClick}>
            Order Now
          </button>
        </li>

        {/* Admin Dashboard */}
        {userRole === 'admin' && (
          <li>
            <Link
              to="/admin"
              className="admin-button"
              onClick={() => setIsMenuOpen(false)}
            >
              Admin Dashboard
            </Link>
          </li>
        )}

        {/* Welcome Message */}
        {userRole && (
          <li className={`welcome-message ${userRole}`}>
            Welcome {userRole.charAt(0).toUpperCase() + userRole.slice(1)}
          </li>
        )}

        {/* Logout */}
        <li>
          <button className="logout-button" onClick={handleLogout}>
            Logout
          </button>
        </li>
      </ul>

      {/* Mobile Burger Menu */}
      <div
        className={`burger ${isMenuOpen ? 'toggle' : ''}`}
        onClick={() => setIsMenuOpen(!isMenuOpen)}
      >
        <div></div>
        <div></div>
        <div></div>
      </div>
    </nav>
  );
}
